#include<bits/stdc++.h>
using namespace std;
inline const int max(const int&x,const int&y)
{
    return x>y?x:y;
}
inline const int min(const int&x,const int&y)
{
    return x<y?x:y;
}
int n,m,f[1010][1010],g[200010],ans[200010];
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        f[u][v]=i;
    }
    for(int k=n;k>=1;k--)
    {
        for(int i=k+1;i<=n;i++)
        {
            g[min(f[i][k],f[k][i])]++;
        }
        for(int i=1;i<=n;i++)
        {
            if(!f[i][k])
            {
                continue;
            }
            if(i>k)
            {
                for(int j=1;j<k;j++)
                {
                    f[i][j]=max(f[i][j],min(f[i][k],f[k][j]));
                }
            }
            else
            {
                for(int j=1;j<=n;j++)
                {
                    f[i][j]=max(f[i][j],min(f[i][k],f[k][j]));
                }
            }
        }
    }
    ans[m+1]=n;
    for(int i=m;i>=1;i--)
    {
        ans[i]=ans[i+1]+g[i];
    }
    for(int i=1;i<=m+1;i++)
    {
        printf("%d ",ans[i]);
    }
    return 0;
}
